#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;int n,m,s[N],d[N],t[N];vector<int> ans[N],S;
typedef pair<int,int> pii;priority_queue<pii> h;pii stk[N];int top;
template<typename T> inline void CV(vector<T> &v){vector<T> t;v.swap(t);}
inline void Solve()
{
//	puts("QAQANQKJDKSDNFKJSDNKLFSDNLKJFNDKSJFSF");
	n=read();m=read();CV(S);
	memset(t+1,0,(n+1)*sizeof(int));while(!h.empty())h.pop();
	rep(1,n,i)++t[read()];rep(1,m,i)s[i]=read();rep(1,m,i)d[i]=read();
	rep(1,m,i){int x=s[i];while(x>d[i])x-=d[i],S.push_back(d[i]);S.push_back(x);}
	rep(1,n,i)if(t[i])h.push({t[i],i});
	for(unsigned v=0;v<S.size();++v)
	{
		top=0;CV(ans[v]);rep(1,S[v],i)
		{
			if(h.empty()){puts("-1");return;}
			pii u=h.top();h.pop();u.first--;if(u.first)stk[++top]=u;
			ans[v].push_back(u.second);
		}
		while(top)h.push(stk[top--]);
	}
	int tmp=0,cnt=1;for(unsigned v=0;v<S.size();++v)
	{
		tmp+=S[v];for(int u:ans[v])printf("%d ",u);
		if(tmp==s[cnt]){tmp=0;++cnt;putchar('\n');}
	}
}
int main()
{
	int T=read();while(T--)Solve();return 0;
}
